          if ! command -v sshpass >/dev/null 2>&1; then
            echo "ERROR: sshpass is required on the Jenkins agent for password-based SSH."
            exit 1
          fi

          for host in ${PROD_HOSTS}; do
            echo "Deploying to ${host}..."

            sshpass -p "${PROD_PASS}" ssh -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null "${PROD_USER}@${host}" "bash -lc '
              set -euo pipefail
              mkdir -p \"${PROD_DEPLOY_DIR}\"
              if command -v systemctl >/dev/null 2>&1; then
                sudo systemctl stop \"${PROD_SERVICE}\" || true
              else
                sudo service \"${PROD_SERVICE}\" stop || true
              fi
            '"

            sshpass -p "${PROD_PASS}" scp -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -r ./* "${PROD_USER}@${host}:${PROD_DEPLOY_DIR}/"

            sshpass -p "${PROD_PASS}" ssh -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null "${PROD_USER}@${host}" "bash -lc '
              set -euo pipefail
              cd \"${PROD_DEPLOY_DIR}\"
